// =============================================
// InputNode.js
// This is the LEFT node where users type their prompt.
// It uses React Flow's Handle component to create
// the connection point on the right side of the node.
// =============================================

import React from "react";
import { Handle, Position } from "@xyflow/react";

function InputNode({ data }) {
  return (
    <div className="custom-node input-node">
      {/* Label at the top */}
      <div className="node-label">📝 Your Prompt</div>

      {/* Textarea for the user to type in */}
      <textarea
        rows={4}
        placeholder="Type your question here... e.g. What is the capital of France?"
        value={data.prompt}
        onChange={(e) => data.onPromptChange(e.target.value)}
      />

      {/*
        Handle = the dot on the edge of the node where the line connects.
        type="source" means the line starts here.
        Position.Right means the dot appears on the right side.
      */}
      <Handle type="source" position={Position.Right} />
    </div>
  );
}

export default InputNode;
